        private static List<string> ParseSelectColumns(string selectParam, HashSet<string> tableColumns)
        {
            if (string.IsNullOrWhiteSpace(selectParam))
            {
                return tableColumns.ToList();
            }

            var requestedColumns = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries)
                .Select(c => c.Trim())
                .ToList();

            foreach (var col in requestedColumns)
            {
                if (!tableColumns.Contains(col))
                {
                    throw new ArgumentException($"Invalid select column: {col}");
                }
            }

            return requestedColumns;
        }

        private static List<FilterCondition> ParseFilters(IQueryCollection query, HashSet<string> tableColumns)
        {
            var filters = new List<FilterCondition>();

            // Filter format: filter_ColumnName_Operator=Value
            // Example: filter_Region_eq=West&filter_Amount_gt=100
            foreach (var key in query.Keys)
            {
                if (!key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                var parts = key.Split('_', 3);
                if (parts.Length != 3)
                {
                    throw new ArgumentException($"Invalid filter format: {key}. Expected format: filter_ColumnName_Operator");
                }

                var columnName = parts[1];
                var operatorName = parts[2];

                if (!tableColumns.Contains(columnName))
                {
                    throw new ArgumentException($"Invalid filter column: {columnName}");
                }

                if (!AllowedOperators.Contains(operatorName))
                {
                    throw new ArgumentException($"Invalid filter operator: {operatorName}. Allowed: {string.Join(", ", AllowedOperators)}");
                }

                var value = query[key].ToString();
                if (string.IsNullOrEmpty(value))
                {
                    throw new ArgumentException($"Filter value cannot be empty for: {key}");
                }

                filters.Add(new FilterCondition
                {
                    Column = columnName,
                    Operator = operatorName,
                    Value = value
                });
            }

            return filters;
        }

        private static (string Query, List<SqlParameter> Parameters) BuildQuery(
            string tableName,
            List<string> selectColumns,
            List<FilterCondition> filters,
            string sortColumn,
            string sortDirection,
            int top,
            int offset)
        {
            var parameters = new List<SqlParameter>();

            // Use bracket-quoted identifiers for table and column names (already validated against whitelist)
            var quotedColumns = selectColumns.Select(c => $"[{c}]");
            var selectClause = string.Join(", ", quotedColumns);

            var query = $"SELECT {selectClause} FROM [{tableName}]";

            // Build WHERE clause with parameterized values
            if (filters.Any())
            {
                var conditions = new List<string>();
                int paramIndex = 0;

                foreach (var filter in filters)
                {
                    var paramName = $"@p{paramIndex}";
                    var quotedColumn = $"[{filter.Column}]";

                    switch (filter.Operator.ToLowerInvariant())
                    {
                        case "eq":
                            conditions.Add($"{quotedColumn} = {paramName}");
                            parameters.Add(new SqlParameter(paramName, filter.Value));
                            break;

                        case "neq":
                            conditions.Add($"{quotedColumn} <> {paramName}");
                            parameters.Add(new SqlParameter(paramName, filter.Value));
                            break;

                        case "gt":
                            conditions.Add($"{quotedColumn} > {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value));
                            break;

                        case "gte":
                            conditions.Add($"{quotedColumn} >= {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value));
                            break;

                        case "lt":
                            conditions.Add($"{quotedColumn} < {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value));
                            break;

                        case "lte":
                            conditions.Add($"{quotedColumn} <= {paramName}");
                            parameters.Add(CreateNumericOrDateParameter(paramName, filter.Value));
                            break;

                        case "like":
                            // Escape special LIKE characters in the user value, then wrap with %
                            var escapedValue = filter.Value
                                .Replace("[", "[[]")
                                .Replace("%", "[%]")
                                .Replace("_", "[_]");
                            conditions.Add($"{quotedColumn} LIKE {paramName}");
                            parameters.Add(new SqlParameter(paramName, $"%{escapedValue}%"));
                            break;

                        case "in":
                            var inValues = filter.Value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                            if (inValues.Length == 0)
                            {
                                throw new ArgumentException($"IN filter requires at least one value for column {filter.Column}");
                            }

                            var inParams = new List<string>();
                            for (int i = 0; i < inValues.Length; i++)
                            {
                                var inParamName = $"@p{paramIndex}_in{i}";
                                inParams.Add(inParamName);
                                parameters.Add(new SqlParameter(inParamName, inValues[i].Trim()));
                            }
                            conditions.Add($"{quotedColumn} IN ({string.Join(", ", inParams)})");
                            break;
                    }

                    paramIndex++;
                }

                query += " WHERE " + string.Join(" AND ", conditions);
            }

            // Add ORDER BY (required for OFFSET/FETCH)
            if (!string.IsNullOrEmpty(sortColumn))
            {
                query += $" ORDER BY [{sortColumn}] {sortDirection}";
            }
            else
            {
                // Default sort for pagination support
                var firstColumn = selectColumns.First();
                query += $" ORDER BY [{firstColumn}] ASC";
            }

            // Add pagination using OFFSET/FETCH (safe since top and offset are validated ints)
            query += $" OFFSET @offset ROWS FETCH NEXT @top ROWS ONLY";
            parameters.Add(new SqlParameter("@offset", SqlDbType.Int) { Value = offset });
            parameters.Add(new SqlParameter("@top", SqlDbType.Int) { Value = top });

            return (query, parameters);
        }

        private static SqlParameter CreateNumericOrDateParameter(string paramName, string value)
        {
            if (decimal.TryParse(value, out var numericValue))
            {
                return new SqlParameter(paramName, SqlDbType.Decimal) { Value = numericValue };
            }

            if (DateTime.TryParse(value, out var dateValue))
            {
                return new SqlParameter(paramName, SqlDbType.DateTime2) { Value = dateValue };
            }

            return new SqlParameter(paramName, value);
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string query,
            List<SqlParameter> parameters,
            ILogger log)
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            if (string.IsNullOrEmpty(connectionString))
            {
                throw new InvalidOperationException("Database connection string is not configured.");
            }

            var results = new List<Dictionary<string, object>>();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand(query, connection))
                {
                    command.CommandTimeout = 30;
                    command.Parameters.AddRange(parameters.ToArray());

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                var columnName = reader.GetName(i);
                                var value = reader.IsDBNull(i) ? null : reader.GetValue(i);
                                row[columnName] = value;
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            return results;
        }

